        def company_week_number(self,date: datetime.date) -> int:
                year_start = datetime.date(date.year, 1, 1)
                days_to_sunday = (6 - year_start.weekday()) % 7 
                first_sunday = year_start + datetime.timedelta(days=days_to_sunday)
                if date < first_sunday:
                        return 1
                delta_days = (date - first_sunday).days
                return delta_days // 7 + 1
    
        def company_week_month(self,year: int, week_number: int) -> int:
                year_start = datetime.date(year, 1, 1)
                days_to_sunday = (6 - year_start.weekday()) % 7
                first_sunday = year_start + datetime.timedelta(days=days_to_sunday)
                start_of_week = first_sunday + datetime.timedelta(weeks=week_number - 1)
                end_of_week = start_of_week + datetime.timedelta(days=6)
                if start_of_week.month != end_of_week.month:
                        mid_of_week = start_of_week + datetime.timedelta(days=3)
                        return mid_of_week.month
                else:
                        return start_of_week.month


